#include "mlpa/reporting/Reporter.h"
#include <sstream>
namespace mlpa { namespace { std::string esc(std::string s){std::string o; for(char c:s){ if(c=='<')o+="&lt;"; else if(c=='>')o+="&gt;"; else if(c=='&')o+="&amp;"; else o+=c;} return o;} }
std::string HtmlReporter::render(const AnalysisResult &r) const { std::ostringstream os; os<<"<!doctype html><html><head><meta charset='utf-8'><title>MLPA Report</title><style>body{font-family:system-ui;margin:2rem}table{border-collapse:collapse;width:100%}td,th{border:1px solid #ddd;padding:.5rem}.Critical{color:#b00020}.High{color:#d35400}.Medium{color:#8a6d00}.Low{color:#2563eb}</style></head><body>"; os<<"<h1>Memory Leak Performance Analyzer Report</h1><h2>Metrics</h2><ul>"<<"<li>Classes: "<<r.metrics.classCount<<"</li><li>Functions: "<<r.metrics.functionCount<<"</li><li>Average function length: "<<r.metrics.averageFunctionLength<<"</li><li>Cyclomatic complexity: "<<r.metrics.totalCyclomaticComplexity<<"</li><li>Max nesting depth: "<<r.metrics.maxNestingDepth<<"</li><li>Quality score: "<<r.metrics.qualityScore<<"</li></ul>"; os<<"<h2>Issues</h2><table><tr><th>Severity</th><th>Rule</th><th>Location</th><th>Description</th><th>Suggested fix</th></tr>"; for(auto &x:r.issues) os<<"<tr><td class='"<<toString(x.severity)<<"'>"<<toString(x.severity)<<"</td><td>"<<esc(x.ruleId)<<"</td><td>"<<esc(x.location.file)<<":"<<x.location.line<<"</td><td><strong>"<<esc(x.title)<<"</strong><br>"<<esc(x.explanation)<<"</td><td>"<<esc(x.suggestion)<<"</td></tr>"; os<<"</table></body></html>\n"; return os.str(); }
}
